#include <bits/stdc++.h>
using namespace std;
struct  node {
    double m;
    double n;
}c[105];
bool cmp(node a1,node b1)
{
    if (a1.n/a1.m>b1.n/b1.m){
		return true;
    }
    else {
		return false;
	}
}
int main(){
    long long a,b;
    cin>>a>>b;
    double d=0;
    for(int i=0;i<a;i++){
        cin>>(c[i].m)>>(c[i].n);
    }
    sort(c,c+a,cmp);
    for(int i=0;i<a;i++){
        if (b-c[i].m>0)
        {
            b-=c[i].m*1.00;
            d+=c[i].n*1.00;
        }
        else
        {
            d+=b/c[i].m*1.00*c[i].n;
            b=0;
            break;
        }
    }
    printf("%.2f",d);
    return 0;
}
